SELECT created_at, created_by
FROM sizing_charts
ORDER BY created_at DESC;

SELECT created_by, COUNT(*) AS total_sizing_charts
FROM sizing_charts
GROUP BY created_by;

SELECT DISTINCT u.user_id, u.user_name, u.email 
FROM users u 
INNER JOIN sizing_charts sc ON u.user_id = sc.created_by;

SELECT r.region_name 
FROM regions r
WHERE r.region_id NOT IN (
  SELECT sc.region_id 
  FROM sizing_charts sc
);
